+    #[test]
+    fn graph_ir_serializes_and_deserializes_without_losing_hierarchy() {
+        let mut graph = super::MermaidGraphIr::default();
+        graph.nodes.push(IrGraphNode {
+            node_id: IrNodeId(0),
